22	#if VM_TRACE
23	#include <verilated_vcd_c.h>
24	VerilatedVcdC* tfp;
25	
26	void _close_trace() {
27		if (tfp) tfp->close();
28	}
29	#endif
30	
31	uint64_t ticks = 0;
32	
33	double sc_time_stamp() {
34		return (double) ticks;
35	}
36	
37	class CSBMaster {
38		struct csb_op {
39			int is_ext;
40			int write;
41			int tries;
42			int reading;
43			uint32_t addr;
44			uint32_t mask;
45			uint32_t data;
46		};
47		
48		std::queue<csb_op> opq;
49		
50		VNV_nvdla *dla;
51		
52		int _test_passed;
53		
54	public:
55		CSBMaster(VNV_nvdla *_dla) {
56			dla = _dla;
57			
58			dla->csb2nvdla_valid = 0;
59			_test_passed = 1;
60		}
61	
62		void read(uint32_t addr, uint32_t mask, uint32_t data) {
63			csb_op op;
64		
65			op.is_ext = 0;
66			op.write = 0;
67			op.addr = addr;
68			op.mask = mask;
69			op.data = data;
70			op.tries = 10;
71			op.reading = 0;
72		
73			opq.push(op);
74		}
75		
76		void write(uint32_t addr, uint32_t data) {
77			csb_op op;
78		
79			op.is_ext = 0;
80			op.write = 1;
81			op.addr = addr;
82			op.data = data;
83		
84			opq.push(op);
85		}
86		
87		void ext_event(int ext) {
88			csb_op op;
89			
90			op.is_ext = ext;
91			opq.push(op);
92		}
93		
94		int eval(int noop) {
95			if (dla->nvdla2csb_wr_complete)
96				printf("(%lu) write complete from CSB\n", ticks);
97			
98			dla->csb2nvdla_valid = 0;
99			if (opq.empty())
100				return 0;
101	
102			csb_op &op = opq.front();
103			
104			if (op.is_ext && !noop) {
105				int ext = op.is_ext;
106				opq.pop();
107				
108				return ext;
109			}
110			
111			if (!op.write && op.reading && dla->nvdla2csb_valid) {
112				printf("(%lu) read response from nvdla: %08x\n", ticks, dla->nvdla2csb_data);
113				
114				if ((dla->nvdla2csb_data & op.mask) != (op.data & op.mask)) {
115					op.reading = 0;
116					op.tries--;
117					printf("(%lu) invalid response -- trying again\n", ticks);
118					if (!op.tries) {
119						printf("(%lu) ERROR: timed out reading response\n", ticks);
120						_test_passed = 0;
121						opq.pop();
122					}
123				} else
124					opq.pop();
125			}
126			
127			if (!op.write && op.reading)
128				return 0;
129			
130			if (noop)
131				return 0;
132			
133			if (!dla->csb2nvdla_ready) {
134				printf("(%lu) CSB stalled...\n", ticks);
135				return 0;
136			}
137			
138			if (op.write) {
139				dla->csb2nvdla_valid = 1;
140				dla->csb2nvdla_addr = op.addr;
141				dla->csb2nvdla_wdat = op.data;
142				dla->csb2nvdla_write = 1;
143				dla->csb2nvdla_nposted = 0;
144				printf("(%lu) write to nvdla: addr %08x, data %08x\n", ticks, op.addr, op.data);
145				opq.pop();
146			} else {
147				dla->csb2nvdla_valid = 1;
148				dla->csb2nvdla_addr = op.addr;
149				dla->csb2nvdla_write = 0;
150				printf("(%lu) read from nvdla: addr %08x\n", ticks, op.addr);
151				
152				op.reading = 1;
153			}
154			
155			return 0;
156		}
157		
158		bool done() {
159			return opq.empty();
160		}
161		
162		int test_passed() {
163			return _test_passed;
164		}
165	};
166	
167	template <typename ADDRTYPE>
168	class AXIResponder {
169	public:
170		struct connections {
171			uint8_t *aw_awvalid;
172			uint8_t *aw_awready;
173			uint8_t *aw_awid;
174			uint8_t *aw_awlen;
175			ADDRTYPE *aw_awaddr;
176			
177			uint8_t *w_wvalid;
178			uint8_t *w_wready;
179			uint32_t *w_wdata;
180			uint64_t *w_wstrb;
181			uint8_t *w_wlast;
182			
183			uint8_t *b_bvalid;
184			uint8_t *b_bready;
185			uint8_t *b_bid;
186			
187			uint8_t *ar_arvalid;
188			uint8_t *ar_arready;
189			uint8_t *ar_arid;
190			uint8_t *ar_arlen;
191			ADDRTYPE *ar_araddr;
192			
193			uint8_t *r_rvalid;
194			uint8_t *r_rready;
195			uint8_t *r_rid;
196			uint8_t *r_rlast;
197			uint32_t *r_rdata;
198		};
199	
200	private:
201	
202	#define AXI_BLOCK_SIZE 4096
203	#define AXI_WIDTH 512
204	
205		const static int AXI_R_LATENCY = 32;
206		const static int AXI_R_DELAY = 0;
207	
208		struct axi_r_txn {
209			int rvalid;
210			int rlast;
211			uint32_t rdata[AXI_WIDTH / 32];
212			uint8_t rid;
213		};
214		std::queue<axi_r_txn> r_fifo;
215		std::queue<axi_r_txn> r0_fifo;
216		
217		struct axi_aw_txn {
218			uint8_t awid;
219			uint32_t awaddr;
220			uint8_t awlen;
221		};
222		std::queue<axi_aw_txn> aw_fifo;
223		
224		struct axi_w_txn {
225			uint32_t wdata[AXI_WIDTH / 32];
226			uint64_t wstrb;
227			uint8_t wlast;
228		};
229		std::queue<axi_w_txn> w_fifo;
230		
231		struct axi_b_txn {
232			uint8_t bid;
233		};
234		std::queue<axi_b_txn> b_fifo;
235		
236		std::map<uint32_t, std::vector<uint8_t> > ram;
237		
238		struct connections dla;
239		const char *name;
240		
241	public:	
242		AXIResponder(struct connections _dla, const char *_name) {
243			dla = _dla;
244			
245			*dla.aw_awready = 1;
246			*dla.w_wready = 1;
247			*dla.b_bvalid = 0;
248			*dla.ar_arready = 1;
249			*dla.r_rvalid = 0;
250			
251			name = _name;
252			
253			/* add some latency... */
254			for (int i = 0; i < AXI_R_LATENCY; i++) {
255				axi_r_txn txn;
256				
257				txn.rvalid = 0;
258				txn.rvalid = 0;
259				txn.rid = 0;
260				txn.rlast = 0;
261				for (int i = 0; i < AXI_WIDTH / 32; i++) {
262					txn.rdata[i] = 0xAAAAAAAA;
263				}
264				
265				r0_fifo.push(txn);
266			}
267		}
268	
269		uint8_t read(uint32_t addr) {
270			ram[addr / AXI_BLOCK_SIZE].resize(AXI_BLOCK_SIZE, 0);
271			return ram[addr / AXI_BLOCK_SIZE][addr % AXI_BLOCK_SIZE];
272		}
273		
274		void write(uint32_t addr, uint8_t data) {
275			ram[addr / AXI_BLOCK_SIZE].resize(AXI_BLOCK_SIZE, 0);
276			ram[addr / AXI_BLOCK_SIZE][addr % AXI_BLOCK_SIZE] = data;
277		}
278		
279		void eval() {
280			/* write request */
281			if (*dla.aw_awvalid && *dla.aw_awready) {
282				printf("(%lu) %s: write request from dla, addr %08lx id %d\n", ticks, name, *dla.aw_awaddr, *dla.aw_awid);
283				
284				axi_aw_txn txn;
285				
286				txn.awid = *dla.aw_awid;
287				txn.awaddr = *dla.aw_awaddr & ~(ADDRTYPE)(AXI_WIDTH / 8 - 1);
288				txn.awlen = *dla.aw_awlen;
289				aw_fifo.push(txn);
290				
291				*dla.aw_awready = 0;
292			} else
293				*dla.aw_awready = 1;
294			
295			/* write data */
296			if (*dla.w_wvalid) {
297				printf("(%lu) %s: write data from dla (%08x %08x...)\n", ticks, name, dla.w_wdata[0], dla.w_wdata[1]);
298				
299				axi_w_txn txn;
300				
301				for (int i = 0; i < AXI_WIDTH / 32; i++)
302					txn.wdata[i] = dla.w_wdata[i];
303				txn.wstrb = *dla.w_wstrb;
304				txn.wlast = *dla.w_wlast;
305				w_fifo.push(txn);
306			}
307			
308			/* read request */
309			if (*dla.ar_arvalid && *dla.ar_arready) {
310				ADDRTYPE addr = *dla.ar_araddr & ~(ADDRTYPE)(AXI_WIDTH / 8 - 1);
311				uint8_t len = *dla.ar_arlen;
312	
313				printf("(%lu) %s: read request from dla, addr %08lx burst %d id %d\n", ticks, name, *dla.ar_araddr, *dla.ar_arlen, *dla.ar_arid);
314				
315				do {
316					axi_r_txn txn;
317	
318					txn.rvalid = 1;
319					txn.rlast = len == 0;
320					txn.rid = *dla.ar_arid;
321				
322					for (int i = 0; i < AXI_WIDTH / 32; i++) {
323						uint32_t da = read(addr + i * 4) + 
324						              (read(addr + i * 4 + 1) << 8) + 
325						              (read(addr + i * 4 + 2) << 16) + 
326						              (read(addr + i * 4 + 3) << 24);
327						txn.rdata[i] = da;
328					}
329	
330					r_fifo.push(txn);
331					
332					addr += AXI_WIDTH / 8;
333				} while (len--);
334				
335				axi_r_txn txn;
336				
337				txn.rvalid = 0;
338				txn.rid = 0;
339				txn.rlast = 0;
340				for (int i = 0; i < AXI_WIDTH / 32; i++) {
341					txn.rdata[i] = 0x55555555;
342				}
343				
344				for (int i = 0; i < AXI_R_DELAY; i++)
345					r_fifo.push(txn);
346				
347				*dla.ar_arready = 0;
348			} else
349				*dla.ar_arready = 1;
350			
351			/* now handle the write FIFOs ... */
352			if (!aw_fifo.empty() && !w_fifo.empty()) {
353				axi_aw_txn &awtxn = aw_fifo.front();
354				axi_w_txn &wtxn = w_fifo.front();
355				
356				if (wtxn.wlast != (awtxn.awlen == 0)) {
357					printf("(%lu) %s: wlast / awlen mismatch\n", ticks, name);
358					abort();
359				}
360				
361				for (int i = 0; i < AXI_WIDTH / 8; i++) {
362					if (!((wtxn.wstrb >> i) & 1))
363						continue;
364					
365					write(awtxn.awaddr + i, (wtxn.wdata[i / 4] >> ((i % 4) * 8)) & 0xFF);
366				}
367				
368				
369				if (wtxn.wlast) {
370					printf("(%lu) %s: write, last tick\n", ticks, name);
371					aw_fifo.pop();
372	
373					axi_b_txn btxn;
374					btxn.bid = awtxn.awid;
375					b_fifo.push(btxn);
376				} else {
377					printf("(%lu) %s: write, ticks remaining\n", ticks, name);
378	
379					awtxn.awlen--;
380					awtxn.awaddr += AXI_WIDTH / 8;
381				}
382				
383				w_fifo.pop();
384			}
385			
386			/* read response */
387			if (!r_fifo.empty()) {
388				axi_r_txn &txn = r_fifo.front();
389				
390				r0_fifo.push(txn);
391				r_fifo.pop();
392			} else {
393				axi_r_txn txn;
394				
395				txn.rvalid = 0;
396				txn.rid = 0;
397				txn.rlast = 0;
398				for (int i = 0; i < AXI_WIDTH / 32; i++) {
399					txn.rdata[i] = 0xAAAAAAAA;
400				}
401				
402				r0_fifo.push(txn);
403			}
404	
405			*dla.r_rvalid = 0;
406			if (*dla.r_rready && !r0_fifo.empty()) {
407				axi_r_txn &txn = r0_fifo.front();
408				
409				*dla.r_rvalid = txn.rvalid;
410				*dla.r_rid = txn.rid;
411				*dla.r_rlast = txn.rlast;
412				for (int i = 0; i < AXI_WIDTH / 32; i++) {
413					dla.r_rdata[i] = txn.rdata[i];
414				}
415				
416				if (txn.rvalid)
417					printf("(%lu) %s: read push: id %d, da %08x %08x %08x %08x\n",
418						ticks, name, txn.rid, txn.rdata[0], txn.rdata[1], txn.rdata[2], txn.rdata[3]);
419				
420				r0_fifo.pop();
421			}
422			
423			/* write response */
424			*dla.b_bvalid = 0;
425			if (*dla.b_bready && !b_fifo.empty()) {
426				*dla.b_bvalid = 1;
427				
428				axi_b_txn &txn = b_fifo.front();
429				*dla.b_bid = txn.bid;
430				b_fifo.pop();
431			}
432		}
433	};
434	
435	class TraceLoader {
436		enum axi_opc {
437			AXI_LOADMEM,
438			AXI_DUMPMEM
439		};
440	
441		struct axi_op {
442			axi_opc opcode;
443			uint32_t addr;
444			uint32_t len;
445			const uint8_t *buf;
446			const char *fname;
447		};
448		std::queue<axi_op> opq;
449		
450		CSBMaster *csb;
451		AXIResponder<uint64_t> *axi_dbb, *axi_cvsram;
452		
453		int _test_passed;
454	
455	public:
456		enum stop_type {	
457			TRACE_CONTINUE = 0,
458			TRACE_AXIEVENT,
459			TRACE_WFI
460		};
461	
462		TraceLoader(CSBMaster *_csb, AXIResponder<uint64_t> *_axi_dbb, AXIResponder<uint64_t> *_axi_cvsram) {
463			csb = _csb;
464			axi_dbb = _axi_dbb;
465			axi_cvsram = _axi_cvsram;
466			_test_passed = 1;
467		}
468		
469		void load(const char *fname) {
470			int fd;
471			fd = open(fname, O_RDONLY);
472			if (fd < 0) {
473				perror("open(trace file)");
474				abort();
475			}
476		
477			unsigned char cmd;
478			int rv;
479	#define VERILY_READ(p, n) do { if (read(fd, (p), (n)) != (n)) { perror("short read"); abort(); } } while(0)
480			do {
481				VERILY_READ(&cmd, 1);
482				
483				switch (cmd) {
484				case 1:
485					printf("CMD: wait\n");
486					csb->ext_event(TRACE_WFI);
487					break;
488				case 2: {
489					uint32_t addr;
490					uint32_t data;
491				
492					VERILY_READ(&addr, 4);
493					VERILY_READ(&data, 4);
494					printf("CMD: write_reg %08x %08x\n", addr, data);
495					csb->write(addr, data);
496					break;
497				}
498				case 3: {
499					uint32_t addr;
500					uint32_t mask;
501					uint32_t data;
502					
503					VERILY_READ(&addr, 4);
504					VERILY_READ(&mask, 4);
505					VERILY_READ(&data, 4);
506					printf("CMD: read_reg %08x %08x %08x\n", addr, mask, data);
507					csb->read(addr, mask, data);
508					break;
509				}
510				case 4: {
511					uint32_t addr;
512					uint32_t len;
513					uint8_t *buf;
514					uint32_t namelen;
515					char *fname;
516					axi_op op;
517					
518					VERILY_READ(&addr, 4);
519					VERILY_READ(&len, 4);
520					buf = (uint8_t *)malloc(len);
521					VERILY_READ(buf, len);
522					
523					VERILY_READ(&namelen, 4);
524					fname = (char *) malloc(namelen+1);
525					VERILY_READ(fname, namelen);
526					fname[namelen] = 0;
527					
528					op.opcode = AXI_DUMPMEM;
529					op.addr = addr;
530					op.len = len;
531					op.buf = buf;
532					op.fname = fname;
533					opq.push(op);
534					csb->ext_event(TRACE_AXIEVENT);
535					
536					printf("CMD: dump_mem %08x bytes from %08x -> %s\n", len, addr, fname);
537					break;
538				}
539				case 5: {
540					uint32_t addr;
541					uint32_t len;
542					uint8_t *buf;
543					axi_op op;
544					
545					VERILY_READ(&addr, 4);
546					VERILY_READ(&len, 4);
547					buf = (uint8_t *)malloc(len);
548					VERILY_READ(buf, len);
549					
550					op.opcode = AXI_LOADMEM;
551					op.addr = addr;
552					op.len = len;
553					op.buf = buf;
554					opq.push(op);
555					csb->ext_event(TRACE_AXIEVENT);
556					
557					printf("CMD: load_mem %08x bytes to %08x\n", len, addr);
558					break;
559				}
560				case 0xFF:
561					printf("CMD: done\n");
562					break;
563				default:
564					printf("unknown command %c\n", cmd);
565					abort();
566				}
567			} while (cmd != 0xFF);
568			
569			close(fd);
570		}
571		
572		void axievent() {
573			if (opq.empty()) {
574				printf("extevent with nothing in the queue?\n");
575				abort();
576			}
577			
578			axi_op &op = opq.front();
579			
580			AXIResponder<uint64_t> *axi;
581			if ((op.addr & 0xF0000000) == 0x50000000)
582				axi = axi_cvsram;
583			else if ((op.addr & 0xF0000000) == 0x80000000)
584				axi = axi_dbb;
585			else {
586				printf("AXI event to bad offset\n");
587				abort();
588			}
589			
590			switch(op.opcode) {
591			case AXI_LOADMEM: {
592				const uint8_t *buf = op.buf;
593				
594				printf("AXI: loading memory at 0x%08x\n", op.addr);
595				while (op.len) {
596					axi->write(op.addr, *buf);
597					buf++;
598					op.addr++;
599					op.len--;
600				}
601				break;
602			}
603			case AXI_DUMPMEM: {
604				int fd;
605				const uint8_t *buf = op.buf;
606				int matched = 1;
607				
608				printf("AXI: dumping memory to %s\n", op.fname);
609				fd = creat(op.fname, 0666);
610				if (!fd) {
611					perror("creat(dumpmem)");
612					break;
613				}
614				while (op.len) {
615					uint8_t da = axi->read(op.addr);
616					write(fd, &da, 1);
617					if (da != *buf && matched) {
618						printf("AXI: FAIL: mismatch at memory address %08x (exp 0x%02x, got 0x%02x), and maybe others too\n", op.addr, *buf, da);
619						matched = 0;
620						_test_passed = 0;
621					}
622					buf++;
623					op.addr++;
624					op.len--;
625				}
626				close(fd);
627				
628				if (matched)
629					printf("AXI: memory dump matched reference\n");
630				break;
631			}
632			default:
633				abort();
634			}
635			
636			opq.pop();
637		}
638		
639		int test_passed() {
640			return _test_passed;
641		}
642	};
643	
644	int main(int argc, const char **argv, char **env) {
645		VNV_nvdla *dla = new VNV_nvdla;
646		CSBMaster *csb = new CSBMaster(dla);
647		
648		AXIResponder<uint64_t>::connections dbbconn = {
