656			.w_wready = &dla->nvdla_core2dbb_w_wready,
657			.w_wdata = dla->nvdla_core2dbb_w_wdata,
658			.w_wstrb = &dla->nvdla_core2dbb_w_wstrb,
659			.w_wlast = &dla->nvdla_core2dbb_w_wlast,
660			
661			.b_bvalid = &dla->nvdla_core2dbb_b_bvalid,
662			.b_bready = &dla->nvdla_core2dbb_b_bready,
663			.b_bid = &dla->nvdla_core2dbb_b_bid,
664	
