677		AXIResponder<uint64_t> *axi_dbb = new AXIResponder<uint64_t>(dbbconn, "DBB");
678	
679		AXIResponder<uint64_t>::connections cvsramconn = {
680			.aw_awvalid = &dla->nvdla_core2cvsram_aw_awvalid,
681			.aw_awready = &dla->nvdla_core2cvsram_aw_awready,
682			.aw_awid = &dla->nvdla_core2cvsram_aw_awid,
683			.aw_awlen = &dla->nvdla_core2cvsram_aw_awlen,
684			.aw_awaddr = &dla->nvdla_core2cvsram_aw_awaddr,
685			
686			.w_wvalid = &dla->nvdla_core2cvsram_w_wvalid,
687			.w_wready = &dla->nvdla_core2cvsram_w_wready,
688			.w_wdata = dla->nvdla_core2cvsram_w_wdata,
689			.w_wstrb = &dla->nvdla_core2cvsram_w_wstrb,
690			.w_wlast = &dla->nvdla_core2cvsram_w_wlast,
691			
692			.b_bvalid = &dla->nvdla_core2cvsram_b_bvalid,
693			.b_bready = &dla->nvdla_core2cvsram_b_bready,
694			.b_bid = &dla->nvdla_core2cvsram_b_bid,
695	
696			.ar_arvalid = &dla->nvdla_core2cvsram_ar_arvalid,
697			.ar_arready = &dla->nvdla_core2cvsram_ar_arready,
698			.ar_arid = &dla->nvdla_core2cvsram_ar_arid,
699			.ar_arlen = &dla->nvdla_core2cvsram_ar_arlen,
700			.ar_araddr = &dla->nvdla_core2cvsram_ar_araddr,
