738		printf("reset...\n");
739		dla->dla_reset_rstn = 1;
740		dla->direct_reset_ = 1;
741		dla->eval();
742		for (int i = 0; i < 20; i++) {
743			dla->dla_core_clk = 1;
744			dla->dla_csb_clk = 1;
745			dla->eval();
746			ticks++;
747	#if VM_TRACE
748			tfp->dump(ticks);
749	#endif
750			
751			dla->dla_core_clk = 0;
752			dla->dla_csb_clk = 0;
753			dla->eval();
754			ticks++;
755	#if VM_TRACE
756			tfp->dump(ticks);
