763		
764		for (int i = 0; i < 20; i++) {
765			dla->dla_core_clk = 1;
766			dla->dla_csb_clk = 1;
767			dla->eval();
768			ticks++;
769	#if VM_TRACE
770			tfp->dump(ticks);
771	#endif
772			
773			dla->dla_core_clk = 0;
774			dla->dla_csb_clk = 0;
775			dla->eval();
776			ticks++;
777	#if VM_TRACE
778			tfp->dump(ticks);
779	#endif
780		}
781		
782		dla->dla_reset_rstn = 1;
783		dla->direct_reset_ = 1;
784		
785		printf("letting buffers clear after reset...\n");
786		for (int i = 0; i < 4096; i++) {
787			dla->dla_core_clk = 1;
788			dla->dla_csb_clk = 1;
789			dla->eval();
790			ticks++;
791	#if VM_TRACE
792			tfp->dump(ticks);
793	#endif
794			
795			dla->dla_core_clk = 0;
796			dla->dla_csb_clk = 0;
797			dla->eval();
798			ticks++;
799	#if VM_TRACE
800			tfp->dump(ticks);
801	#endif
802		}
803	
804		printf("running trace...\n");
805		uint32_t quiesc_timer = 200;
806		int waiting = 0;
807		while (!csb->done() || (quiesc_timer--)) {
808			int extevent;
809			
810			extevent = csb->eval(waiting);
811			
812			if (extevent == TraceLoader::TRACE_AXIEVENT)
813				trace->axievent();
814			else if (extevent == TraceLoader::TRACE_WFI) {
815				waiting = 1;
816				printf("(%lu) waiting for interrupt...\n", ticks);
817			}
818			
819			if (waiting && dla->dla_intr) {
820				printf("(%lu) interrupt!\n", ticks);
821				waiting = 0;
822			}
823				
824			axi_dbb->eval();
825			axi_cvsram->eval();
826	
827			dla->dla_core_clk = 1;
828			dla->dla_csb_clk = 1;
829			dla->eval();
830			ticks++;
831	#if VM_TRACE
832			tfp->dump(ticks);
833	#endif
834			
835			dla->dla_core_clk = 0;
836			dla->dla_csb_clk = 0;
837			dla->eval();
838			ticks++;
839	#if VM_TRACE
840			tfp->dump(ticks);
841	#endif
842		}
843		
844		printf("done at %lu ticks\n", ticks);
845	
846		if (!trace->test_passed()) {
847			printf("*** FAIL: test failed due to output mismatch\n");
848			return 1;
849		}
850		
851		if (!csb->test_passed()) {
852			printf("*** FAIL: test failed due to CSB read mismatch\n");
853			return 2;
854		}
